mapper.select:
SELECT COUNT(*)
FROM empproject
WHERE empid = #{empId}

	AND projectid = #{projectid, jdbcType=NUMERIC}

AND UPPER(role) = 'M'

SELECT COUNT(*) FROM projectnotice WHERE state = 1
AND projectid = #{projectid, jdbcType=NUMERIC}
AND ( subject LIKE '%' || #{keyword} || '%' OR content LIKE '%' || #{keyword} || '%' )

SELECT n.noticenum, n.projectid, n.subject, n.content, n.hitcount, n.isnotice, n.state, TO_CHAR(n.regdate,'YYYY-MM-DD') regdate, TO_CHAR(n.updatedate,'YYYY-MM-DD') updatedate, n.authorempid, e.name authorName, p.title projectName
FROM projectnotice n LEFT JOIN employee2 e ON n.authorempid = e.empid LEFT JOIN project p ON n.projectid = p.projectid
WHERE n.noticenum = #{noticenum}
